const p = msg.payload;
const lux = (-0.32466 * p.red + 1.57837 * p.green + -0.73191 * p.blue).toFixed(0);
const rPct = (p.clear > 0 ? (p.red / p.clear * 100).toFixed(1) : '0.0');
const gPct = (p.clear > 0 ? (p.green / p.clear * 100).toFixed(1) : '0.0');
const bPct = (p.clear > 0 ? (p.blue / p.clear * 100).toFixed(1) : '0.0');
msg.payload = 'C=' + p.clear + ' R=' + p.red + '(' + rPct + '%) G=' + p.green + '(' + gPct + '%) B=' + p.blue + '(' + bPct + '%) lux~' + lux;
return msg;
